import { FileIcons } from '../../FileIcons/index.js';

const archiveMimeNameList = [
    'application/java-archive',
    'application/x-rar-compressed',
    'application/x-zip-compressed',
    'application/x-gtar',
    'application/x-gzip',
    'application/x-ms-wim',
    'application/x-xar',
    'application/zip',
    'application/vnd.rar',
    'application/x-archive',
    'application/x-cpio',
    'application/x-shar',
    'application/x-sbx',
    'application/x-tar',
    'application/x-brotli',
    'application/gzip',
    'application/x-lzip',
    'application/x-7z-compressed',
    'application/octet-stream',
    'application/x-freearc',
];
const wordMimeNameList = ['msword', 'wordprocessingml', 'ms-word'];
const excelMimeNameList = ['ms-excel', 'spreadsheetml', '/csv'];
const powerpointMimeNameList = ['ms-powerpoint', 'presentationml'];
// todo подумать как сделать по нормальному
const mapFileIcon = (type) => {
    // todo пока не найду баг как сюда updef попадал
    if (type) {
        if (type.startsWith('image/')) {
            return FileIcons.ImageMedium({});
        }
        if (type.startsWith('video/')) {
            return FileIcons.VideoMedium({});
        }
        if (type.startsWith('audio/')) {
            return FileIcons.SoundMedium({});
        }
        // Check for CSV files before general text check
        if (type === 'text/csv') {
            return FileIcons.TableMedium({});
        }
        if (type.startsWith('text/')) {
            return FileIcons.TextMedium({});
        }
        if (type.startsWith('application/')) {
            if (type === 'application/pdf') {
                return FileIcons.PdfMedium({});
            }
            //  Для офисных документов так, потому что там можно понять по ключевым словам
            for (const wordType of wordMimeNameList) {
                if (type.includes(wordType)) {
                    return FileIcons.TextMedium({});
                }
            }
            for (const sheetType of excelMimeNameList) {
                if (type.includes(sheetType)) {
                    return FileIcons.TableMedium({});
                }
            }
            for (const presentationType of powerpointMimeNameList) {
                if (type.includes(presentationType)) {
                    return FileIcons.PresentationMedium({});
                }
            }
            //  для архивов полные названия, потому что их правая часть может включаться и в другие типы.
            if (archiveMimeNameList.includes(type)) {
                return FileIcons.ArchiveMedium({});
            }
        }
    }
    return FileIcons.OtherMedium({});
};

export { mapFileIcon };
